// Define all 3 client sites
const clients = [
  { project: 'aarohaom', url: 'https://aarohaom.com' },
  { project: 'blackpanda', url: 'https://blackpandaenterprises.com' },
  { project: 'ageddentistry', url: 'https://ageddentistry.org' }
];
return clients.map(c => ({ json: c }));

const mobileData = $('PageSpeed Mobile').item.json;
const desktopData = $('PageSpeed Desktop').item.json;
const project = $('Define Client Sites').item.json.project;

const mobileScore = Math.round((mobileData.lighthouseResult?.categories?.performance?.score || 0) * 100);
const desktopScore = Math.round((desktopData.lighthouseResult?.categories?.performance?.score || 0) * 100);

const audits = mobileData.lighthouseResult?.audits || {};
const lcp = parseFloat((audits['largest-contentful-paint']?.numericValue / 1000 || 0).toFixed(2));
const fid = parseFloat((audits['max-potential-fid']?.numericValue || 0).toFixed(2));
const cls = parseFloat((audits['cumulative-layout-shift']?.numericValue || 0).toFixed(3));

return [{ json: {
  project,
  mobileScore,
  desktopScore,
  lcp,
  fid,
  cls,
  needsAlert: mobileScore < 70,
  checkedAt: new Date().toISOString()
}}];

