// Aggregate all results into a weekly summary
const allItems = $input.all();
const results = allItems.map(item => item.json);

const redAlerts = results.filter(r => r.needsAlert);
const goodSites = results.filter(r => !r.needsAlert);

let summaryText = `*SEO Weekly PageSpeed Report — ${new Date().toDateString()}*\n\n`;

results.forEach(r => {
  const emoji = r.mobileScore < 50 ? '🔴' : r.mobileScore < 70 ? '🟡' : '🟢';
  summaryText += `${emoji} *${r.project}* — Mobile: ${r.mobileScore} | Desktop: ${r.desktopScore}\n`;
  summaryText += `   LCP: ${r.lcp}s | CLS: ${r.cls}\n`;
});

if (redAlerts.length > 0) {
  summaryText += `\n⚠️ *${redAlerts.length} site(s) need immediate attention (mobile score < 70)*`;
}

return [{ json: { summaryText, redAlerts, goodSites, allResults: results } }];
